module top_module(
    input               clk,
    input    [31:0]     in_data,

    output              gpio_sinal,
    output              mem_sinal
);reg                     obf_gpio_reg;

always @(posedge clk)
begin
    if(in_data>1023) obf_gpio_reg <= 1;
    else obf_gpio_reg <= 0;
end

assign gpio_sinal = obf_gpio_reg;
assign mem_sinal = ~obf_gpio_reg;

endmodule
